import './App.css';
import video_bg from './assets/home-bg.mp4';
import Navbar from './navbar';

function App() {
  return (
    <div className="App">
      <header className="App-header"> </header>


      <video className='video_bg' autoPlay loop muted>
          <source src={video_bg} type='video/mp4' />
      </video>
    </div>
  );
}

export default App;
